func TestNovelOpportunityLowerCompetitionScoresHigher(t *testing.T) {
	base := keywordSignals{
		Keyword: "ceramic mug",
		Stats: map[string]any{
			"avg_searches": 2000.0,
			"difficulty":   20.0,
		},
	}
	lowerCompetition := base
	lowerCompetition.Stats = map[string]any{
		"avg_searches": 2000.0,
		"competition":  1000.0,
		"difficulty":   20.0,
	}
	higherCompetition := base
	higherCompetition.Stats = map[string]any{
		"avg_searches": 2000.0,
		"competition":  90000.0,
		"difficulty":   20.0,
	}

	low := scoreKeyword(lowerCompetition)
	high := scoreKeyword(higherCompetition)
	if low.Score <= high.Score {
		t.Fatalf("lower competition score = %.1f, higher competition score = %.1f", low.Score, high.Score)
	}
}
